import { NextResponse } from "next/server";
import { sql, initBlogTable } from "@/lib/db";
import fs from "fs";
import path from "path";

/**
 * Seed endpoint ΓÇö migrates existing posts from data/posts.json into Vercel Postgres.
 * Run once after setting up the database. Protected by CRON_SECRET.
 * 
 * Usage: POST /api/admin/seed-blog (with Authorization: Bearer <CRON_SECRET>)
 */
export async function POST(request: Request) {
  const authHeader = request.headers.get("authorization");
  if (authHeader !== `Bearer ${process.env.CRON_SECRET}`) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  if (!process.env.POSTGRES_URL) {
    return NextResponse.json({ error: "POSTGRES_URL not configured" }, { status: 500 });
  }

  try {
    await initBlogTable();

    // Read existing posts from JSON
    const filePath = path.join(process.cwd(), "data", "posts.json");
    if (!fs.existsSync(filePath)) {
      return NextResponse.json({ message: "No posts.json found, nothing to seed." });
    }

    const posts = JSON.parse(fs.readFileSync(filePath, "utf-8"));
    let seeded = 0;

    for (const post of posts) {
      try {
        await sql`
          INSERT INTO blog_posts (slug, title, excerpt, date, read_time, category, content)
          VALUES (
            ${post.slug},
            ${post.title},
            ${post.excerpt},
            ${post.date},
            ${post.readTime || "5 min read"},
            ${post.category || "Web Development"},
            ${post.content}
          )
          ON CONFLICT (slug) DO NOTHING
        `;
        seeded++;
      } catch (e: any) {
        console.error(`Failed to seed: ${post.slug}`, e.message);
      }
    }

    return NextResponse.json({
      success: true,
      message: `Seeded ${seeded} of ${posts.length} posts into Vercel Postgres.`,
    });
  } catch (error: any) {
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { GoogleGenerativeAI } from "@google/generative-ai";
import { NextResponse } from "next/server";

const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY || "");

export async function POST(req: Request) {
  try {
    const { url } = await req.json();

    if (!url) {
      return NextResponse.json({ error: "URL is required" }, { status: 400 });
    }

    if (!process.env.GEMINI_API_KEY) {
      return NextResponse.json({ error: "Gemini API key is not configured" }, { status: 500 });
    }

    // Using exactly one stable model for consistency
    const model = genAI.getGenerativeModel({
      model: "gemini-2.5-flash",
      generationConfig: {
        responseMimeType: "application/json",
        temperature: 0.9,
      },
    });

    const prompt = `
      You are a World-Class Conversion Rate Optimization (CRO) and SEO Specialist working for "Arcova Studio", a premium web design agency in Agra, India.
      
      Website URL: ${url}
      
      Generate a professional website audit report in JSON format:
      {
        "score": number (0-100),
        "scores": { "seo": number, "performance": number, "design": number, "security": number },
        "criticalImprovements": string[],
        "summary": string
      }
      
      Tone: Technical, provactive, Agra-market focused.
    `;

    const result = await model.generateContent(prompt);
    const responseText = result.response.text();
    return NextResponse.json(JSON.parse(responseText.trim()));

  } catch (error: any) {
    console.error("Audit API Error:", error.message);

    let errorMessage = "AI Generation failed. Please try again later.";
    let status = 500;

    if (error.status === 429) {
      errorMessage = "AI Quota Exceeded. Please check your Gemini API plan.";
      status = 429;
    } else if (error.status === 400) {
      errorMessage = "Invalid request. Please check your website URL.";
      status = 400;
    }

    return NextResponse.json({ error: errorMessage }, { status });
  }
}

import { NextResponse } from "next/server";
import { generateBlogWithGemini } from "@/lib/gemini";
import { CITIES, SERVICES } from "@/lib/seo-data";
import { sql, initBlogTable } from "@/lib/db";

/**
 * Cron endpoint for automated blog generation.
 * Called by Vercel Cron on Mon/Wed/Fri at 6:00 AM IST.
 * 
 * Secured with CRON_SECRET environment variable.
 */
export async function GET(request: Request) {
  // Verify cron secret
  const authHeader = request.headers.get("authorization");
  if (authHeader !== `Bearer ${process.env.CRON_SECRET}`) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  if (!process.env.POSTGRES_URL) {
    return NextResponse.json({ error: "POSTGRES_URL not configured" }, { status: 500 });
  }

  try {
    await initBlogTable();

    // Pick random city and service
    const city = CITIES[Math.floor(Math.random() * CITIES.length)].name;
    const service = SERVICES[Math.floor(Math.random() * SERVICES.length)].name;

    // Generate blog post
    const newPost = await generateBlogWithGemini(city, service);

    const slug = newPost.slug || newPost.title.toLowerCase().replace(/[^\w\s-]/g, "").replace(/\s+/g, "-");
    const date = new Date().toISOString().split("T")[0];

    // Save to database
    await sql`
      INSERT INTO blog_posts (slug, title, excerpt, date, read_time, category, content)
      VALUES (
        ${slug},
        ${newPost.title},
        ${newPost.excerpt},
        ${date},
        ${newPost.readTime || "5 min read"},
        ${newPost.category || "Web Development"},
        ${newPost.content}
      )
      ON CONFLICT (slug) DO NOTHING
    `;

    console.log(`[CRON] Blog generated: "${newPost.title}" for ${city} / ${service}`);

    return NextResponse.json({
      success: true,
      post: { title: newPost.title, slug, city, service },
    });
  } catch (error: any) {
    console.error("[CRON] Blog generation failed:", error.message);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

