              <Button 
                size="lg" 
                className="w-full rounded-2xl bg-accent text-accent-foreground font-black uppercase tracking-widest shadow-xl shadow-accent/20 border-0"
                onClick={() => {
                  setIsOpen(false);
                  document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' });
                }}
